import { useCallback, useEffect, useRef } from 'react';
import { NavigationProp, useFocusEffect, useNavigation } from '@react-navigation/native';
import { Dimensions } from 'react-native';

import theme from '../../styles/theme';
import { InformationList, InvoiceCashbackProps, UseInvoiceCashbackOnboardingReturn } from './models';
import { PropsRootStack } from '../../routes/Models';
import { eventScreenViewV3, eventSelectContent } from '~/constants/functions';
import { useRootStore } from '~/store';
import { getParameterPointsProgram, getPointsProducts } from '../../services/services';
import { ParameterPointsProgramStatus, PointsBalanceStatus } from '../../services/models';

export function useInvoiceCashbackOnboardingScreen(
  params?: InvoiceCashbackProps
): UseInvoiceCashbackOnboardingReturn {
  const { width } = Dimensions.get('window');
  const hasFocused = useRef(false);
  const navigation = useNavigation<NavigationProp<PropsRootStack>>();

  const { points, status: balanceStatus } = useRootStore((state) => state.pointsBalance);
  const { status: paramStatus, pointsQuantity } = useRootStore((state) => state.parameterPointsProgram);
  const { parameterPointsProgramActions } = useRootStore.getState();

  const isLoadingBalance = balanceStatus === PointsBalanceStatus.LOADING;
  const isErrorBalance = balanceStatus === PointsBalanceStatus.ERROR;
  const isLoadingParameterization = paramStatus === ParameterPointsProgramStatus.LOADING;
  const isErrorParameterization = paramStatus === ParameterPointsProgramStatus.ERROR;

  const conversionFactor = params?.route?.params?.conversionFactor ?? 0;
  const campaingId = params?.route?.params?.campaingId ?? '';
  const productCode = params?.route?.params?.productCode ?? '';
  const pointsPrice = (points || 0) * conversionFactor;

  useFocusEffect(
    useCallback(() => {
      if (!hasFocused.current) {
        eventScreenViewV3('desconto_fatura_onboarding', 'hub_recompensas_spmais', 'monetizacao', {
          location_1: 'monetizacao',
          location_2: 'hub_recompensas_spmais',
          location_3: 'desconto_fatura_onboarding',
        });
        hasFocused.current = true;
      }
      return () => {
        hasFocused.current = false;
      };
    }, [])
  );

  useEffect(() => {
    getParameterPointsProgram();
  }, []);

  const handleGoBack = useCallback(() => {
    navigation.goBack();
  }, [navigation]);

  const requestAll = useCallback(() => {
    parameterPointsProgramActions.setStatus(ParameterPointsProgramStatus.IDLE);
    getParameterPointsProgram();
    getPointsProducts();
  }, [parameterPointsProgramActions]);

  const handleRetry = useCallback(() => {
    if (isErrorParameterization) {
      requestAll();
    }
  }, [isErrorParameterization, requestAll]);

  const handleContinue = useCallback(() => {
    navigation.navigate('InvoiceCashbackPoints', {
      conversionFactor,
      campaingId,
      productCode,
    });

    eventSelectContent({
      content_type: 'cta',
      content_id: 'continuar',
      location_1: 'monetizacao',
      location_2: 'hub_recompensas_spmais',
      location_3: 'desconto_fatura_onboarding',
    });
  }, [navigation, conversionFactor, campaingId, productCode]);

  const invoiceList = useCallback((): InformationList[] => {
    const whiteShape = theme.colors.LIGHT_BASE_01;
    const fintechColor = theme.colors.SECONDARY_COLOR_02;

    const finalPrice = pointsQuantity * conversionFactor;
    const formattedPrice = new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL',
    }).format(finalPrice);

    return [
      {
        type: 'default',
        icon: 'icon-switch-vertical',
        iconColor: fintechColor,
        iconColorShape: whiteShape,
        description: `Cada ${pointsQuantity} pontos valem ${formattedPrice} no cashback`,
      },
      {
        type: 'default',
        icon: 'icon-calendar',
        iconColor: fintechColor,
        iconColorShape: whiteShape,
        description: 'Você define quanto cashback quer aplicar na sua fatura aberta',
      },
      {
        type: 'default',
        icon: 'icon-payment-invoice',
        iconColor: fintechColor,
        iconColorShape: whiteShape,
        description: 'Se o valor for maior que o da fatura, a diferença será aplicada nas próximas',
      },
      {
        type: 'default',
        icon: 'icon-clock',
        iconColor: fintechColor,
        iconColorShape: whiteShape,
        description: 'O cashback acontece em até 72h',
      },
    ];
  }, [pointsQuantity, conversionFactor]);

  const items: InformationList[] = invoiceList().map((item) => ({
    icon: item.icon,
    iconColor: item.iconColor,
    description: item.description,
    iconColorShape: item.iconColorShape,
    type: item.type,
  }));

  return {
    handleGoBack,
    handleContinue,
    handleRetry,
    items,
    hasError: isErrorBalance,
    hasLoading: isLoadingBalance,
    cashbackInvoiceList: invoiceList(),
    pts: points || 0,
    price: pointsPrice,
    pointsQuantity,
    conversionFactor,
    width,
    isLoadingParameterization,
    isErrorParameterization,
  };
}

export { default } from './view';

