export enum PointsBalanceStatus {
  IDLE = 'idle',
  LOADING = 'loading',
  SUCCESS = 'success',
  ERROR = 'error',
}

export type TransactionType = 'CREDIT' | 'RESCUE' | 'EXPIRED' | 'REFUNDED';

export const TYPE_LABELS: Record<TransactionType, string> = {
  CREDIT: 'Ganhos',
  RESCUE: 'Usados',
  EXPIRED: 'Expirados',
  REFUNDED: 'Estornados',
};

export const PERIOD_DAYS_MAP: Record<number, number> = {
  0: 7,
  1: 15,
  2: 30,
  3: 60,
  4: 90,
};

export interface PointsTransaction {
  id: string;
  date: string;
  description: string;
  type: TransactionType;
  amount: number;
  currencyValue: number;
  icon: string;
  details: {
    provider: string;
    extraInfo: string;
    fields: Array<{
      label: string;
      value: string;
    }>;
  };
}

export interface PaginationDto {
  page: number;
  pageSize: number;
  total: number;
  totalPages: number;
}

